13	      expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet" }])).toBe(71);
14	    });
15	    it.todo("single staff (newcomer, plain) → premium 93 G (80 base + 8 first-insurance + 5 fee)");
16	    it.todo("single potion (newcomer, plain) → premium 49 G (40 base + 4 first-insurance + 5 fee)");
17	  });
18	
19	  describe("quote — component building block", () => {
20	    it.todo("2 runes (no block) → premium 60 G (50 base + 5 first-insurance + 5 fee)");
21	    it.todo("3 runes (block applies) → premium 71 G (60 base + 6 first-insurance + 5 fee)");
22	    it.todo("4 runes (no block — block requires exactly 3) → premium 115 G (100 base + 10 first-insurance + 5 fee)");
