35	
36	  describe("quote — modifier scope on multi-item policies", () => {
37	    it.todo("cursed sword + plain amulet (newcomer) → premium 231 G (policy base 160 + 50 curse on sword only + 10 first-ins sword + 6 first-ins amulet + 5 fee)");
38	  });
39	
40	  describe("quote — integration examples", () => {
41	    it.todo("newcomer with a cursed sword (steel, enchant 3), 0 years, first contract → premium 165 G (100 base + 50 curse + 10 first-insurance + 5 fee)");
42	    it.todo("long-standing customer's second contract: cursed sword (enchant 7), 3 years, second quote → premium 160 G (100 + 50 + 30 − 20 + 10 − 15 + 5)");
43	  });
44	
45	  describe("claim — standard reimbursement", () => {
46	    it.todo("regular sword (steel, enchant 3), damage 500 G → payout 400 G (full minus 100 deductible)");
47	    it.todo("rune (no enchant/material), damage 200 G → payout 100 G (full minus 100 deductible)");
48	  });
49	
50	  describe("claim — enchantment and dragon-material clauses", () => {
51	    it.todo("dragon sword enchant exactly 8, damage 1000 G → payout 400 G (50%% rule wins, then deductible: 500 − 100)");
52	    it.todo("dragon sword enchant 9, damage 1000 G → payout 400 G (both clauses; 50%% wins, then deductible)");
53	    it.todo("dragon sword enchant 5, damage 800 G → payout 700 G (only dragon clause: full reimbursement, then deductible)");
54	    it.todo("steel sword enchant 9, damage 1000 G → payout 400 G (only high-enchant clause: 50%% first, then deductible)");
55	  });
56	
57	  describe("claim — deductible per damage event", () => {
58	    it.todo("dragon attack damages sword (500 G) + amulet (300 G) → payout 600 G (deductible applies once per damaged item)");
59	    it.todo("two-sword policy, dragon attack with two sword damage entries (500 + 400) → payout 700 G (each entry deducted: 400 + 300)");
60	  });
61	
62	  describe("claim — insurance sum and cap", () => {
63	    it.todo("policy of sword + amulet → insurance sum 1600 G, cap 3200 G");
64	    it.todo("policy with cursed sword (premium 165 G after modifiers) → cap still 2000 G (based on unmodified insurance value)");
65	    it.todo("policy of sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only), cap 3500 G");
