79	
80	  describe("CLI — error handling (exit non-zero, stderr)", () => {
81	    it.todo("CLI: quote includes unknown item type (e.g. broomstick) → exits non-zero, error on stderr, no `results` on stdout");
82	    it.todo("CLI: claim references an item not in the policy (e.g. amulet damaged when only a sword insured) → exits non-zero, error on stderr");
83	    it.todo("CLI: claim damage entry with negative amount → exits non-zero, error on stderr");
84	    it.todo("CLI: claim contains more damage entries of a type than the policy covers (two sword damages, one sword insured) → exits non-zero, error on stderr");
