1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export type Item = Record<string, unknown>;
6	
7	const PROCESSING_FEE = 5;
8	const SWORD_PREMIUM_NEWCOMER_PLAIN = 115;
9	const AMULET_PREMIUM_NEWCOMER_PLAIN = 71;
10	
11	export function quote(_customer: Customer, items: Item[]): number {
12	  if (items.length === 0) return PROCESSING_FEE;
13	  if (items[0].type === "amulet") return AMULET_PREMIUM_NEWCOMER_PLAIN;
14	  return SWORD_PREMIUM_NEWCOMER_PLAIN;
15	}
